526       auto Result = decompose(Op0, Preconditions, IsSigned, DL);
527       Result.mul(CI->getSExtValue());
528       return Result;
529     }
530 
531     // (shl nsw x, shift) is (mul nsw x, (1<<shift)), with the exception of
532     // shift == bw-1.
