558   if (match(V, m_SExt(m_Value(Op0)))) {
559     V = Op0;
560     Preconditions.emplace_back(CmpInst::ICMP_SGE, Op0,
561                                ConstantInt::get(Op0->getType(), 0));
562   }
563 
564   Value *Op1;
565   ConstantInt *CI;
